 646→// JobsStatistics is the resolver for the jobsStatistics field.
 647→func (r *queryResolver) JobsStatistics(ctx context.Context, filter []*model.JobFilter, metrics []string, page *model.PageRequest, sortBy *model.SortByAggregate, groupBy *model.Aggregate, numDurationBins *string, numMetricBins *int) ([]*model.JobsStatistics, error) {
 648→	var err error
 649→	var stats []*model.JobsStatistics
 650→
 651→	// Top Level Defaults
 652→	defaultDurationBins := "1h"
 653→	defaultMetricBins := 10
 654→
 655→	// Build requested fields map for selective column computation
 656→	statsFields := []string{
 657→		"totalJobs", "totalUsers", "totalWalltime", "totalNodes", "totalCores",
 658→		"totalAccs", "totalNodeHours", "totalCoreHours", "totalAccHours", "runningJobs", "shortJobs",
 659→	}
 660→	reqFields := make(map[string]bool, len(statsFields))
 661→	fetchedMainStats := false
 662→	for _, f := range statsFields {
 663→		if requireField(ctx, f) {
 664→			reqFields[f] = true
 665→			if f != "runningJobs" && f != "shortJobs" {
 666→				fetchedMainStats = true
 667→			}
 668→		}
 669→	}
 670→
 671→	if fetchedMainStats {
 672→		if groupBy == nil {
 673→			stats, err = r.Repo.JobsStats(ctx, filter, reqFields)
 674→		} else {
 675→			startGrouped := time.Now()
 676→			// Use request-scoped cache: multiple aliases with same (filter, groupBy)
 677→			// but different sortBy/page hit the DB only once.
 678→			if cache := getStatsGroupCache(ctx); cache != nil {
 679→				key := statsCacheKey(filter, groupBy, reqFields)
 680→				var allStats []*model.JobsStatistics
 681→				allStats, err = cache.getOrCompute(key, func() ([]*model.JobsStatistics, error) {
 682→					return r.Repo.JobsStatsGrouped(ctx, filter, nil, nil, groupBy, reqFields)
 683→				})
 684→				if err == nil {
 685→					stats = sortAndPageStats(allStats, sortBy, page)
 686→				}
 687→			} else {
 688→				stats, err = r.Repo.JobsStatsGrouped(ctx, filter, page, sortBy, groupBy, reqFields)
 689→			}
 690→			cclog.Infof("Timer JobsStatsGrouped call: %s", time.Since(startGrouped))
 691→		}
 692→	} else {
 693→		stats = make([]*model.JobsStatistics, 0, 1)
 694→		stats = append(stats, &model.JobsStatistics{})
 695→	}
 696→
 697→	// runningJobs and shortJobs are already inlined in JobsStats/JobsStatsGrouped.
 698→	// Only run separate count queries if main stats were not fetched.
 699→	if !fetchedMainStats {
 700→		if groupBy != nil {
 701→			if requireField(ctx, "shortJobs") {
 702→				stats, err = r.Repo.AddJobCountGrouped(ctx, filter, groupBy, stats, "short")
 703→			}
 704→			if requireField(ctx, "runningJobs") {
 705→				stats, err = r.Repo.AddJobCountGrouped(ctx, filter, groupBy, stats, "running")
 706→			}
 707→		} else {
 708→			if requireField(ctx, "shortJobs") {
 709→				stats, err = r.Repo.AddJobCount(ctx, filter, stats, "short")
 710→			}
 711→			if requireField(ctx, "runningJobs") {
 712→				stats, err = r.Repo.AddJobCount(ctx, filter, stats, "running")
 713→			}
 714→		}
 715→	}
 716→
 717→	if err != nil {
 718→		return nil, err
 719→	}
 720→
 721→	if requireField(ctx, "histDuration") || requireField(ctx, "histNumNodes") || requireField(ctx, "histNumCores") || requireField(ctx, "histNumAccs") {
 722→
 723→		if numDurationBins == nil {
 724→			numDurationBins = &defaultDurationBins
 725→		}
 726→
 727→		if groupBy == nil {
 728→			stats[0], err = r.Repo.AddHistograms(ctx, filter, stats[0], numDurationBins)
 729→			if err != nil {
 730→				return nil, err
 731→			}
 732→		} else {
 733→			return nil, errors.New("histograms only implemented without groupBy argument")
 734→		}
 735→	}
 736→
 737→	if requireField(ctx, "histMetrics") {
 738→
 739→		if numMetricBins == nil {
 740→			numMetricBins = &defaultMetricBins
 741→		}
 742→
 743→		if groupBy == nil {
 744→			stats[0], err = r.Repo.AddMetricHistograms(ctx, filter, metrics, stats[0], numMetricBins)
 745→			if err != nil {
 746→				return nil, err
 747→			}
 748→		} else {
 749→			return nil, errors.New("metric histograms only implemented without groupBy argument")
 750→		}
 751→	}
 752→
 753→	return stats, nil
 754→}
