 945→// ClusterMetrics is the resolver for the clusterMetrics field.
 946→func (r *queryResolver) ClusterMetrics(ctx context.Context, cluster string, metrics []string, from time.Time, to time.Time) (*model.ClusterMetrics, error) {
 947→	user := repository.GetUserFromContext(ctx)
 948→	if user != nil && !user.HasAnyRole([]schema.Role{schema.RoleAdmin, schema.RoleSupport}) {
 949→		return nil, errors.New("you need to be administrator or support staff for this query")
 950→	}
 951→
 952→	if metrics == nil {
 953→		for _, mc := range archive.GetCluster(cluster).MetricConfig {
 954→			metrics = append(metrics, mc.Name)
 955→		}
 956→	}
 957→
 958→	// 'nodes' == nil -> Defaults to all nodes of cluster for existing query workflow
 959→	scopes := []schema.MetricScope{"node"}
 960→	data, err := metricdispatch.LoadNodeData(cluster, metrics, nil, scopes, from, to, ctx)
 961→	if err != nil {
 962→		cclog.Warn("error while loading node data")
 963→		return nil, err
 964→	}
 965→
 966→	clusterMetricData := make([]*model.ClusterMetricWithName, 0)
 967→	clusterMetrics := model.ClusterMetrics{NodeCount: 0, Metrics: clusterMetricData}
 968→
 969→	collectorTimestep := make(map[string]int)
 970→	collectorUnit := make(map[string]schema.Unit)
 971→	collectorData := make(map[string][]schema.Float)
 972→
 973→	for _, metrics := range data {
 974→		clusterMetrics.NodeCount += 1
 975→		for metric, scopedMetrics := range metrics {
 976→			for _, scopedMetric := range scopedMetrics {
 977→				// Collect Info Once
 978→				_, okTimestep := collectorTimestep[metric]
 979→				if !okTimestep {
 980→					collectorTimestep[metric] = scopedMetric.Timestep
 981→				}
 982→				_, okUnit := collectorUnit[metric]
 983→				if !okUnit {
 984→					collectorUnit[metric] = scopedMetric.Unit
 985→				}
 986→				// Collect Data
 987→				for _, ser := range scopedMetric.Series {
 988→					_, okData := collectorData[metric]
 989→					// Init With Datasize > 0
 990→					if !okData && len(ser.Data) != 0 {
 991→						collectorData[metric] = make([]schema.Float, len(ser.Data))
 992→					} else if !okData {
 993→						cclog.Debugf("[SCHEMARESOLVER] clusterMetrics skip init: no data -> %s at %s; size %d", metric, ser.Hostname, len(ser.Data))
 994→					}
 995→					// Sum if init'd and matching size
 996→					if okData && len(ser.Data) == len(collectorData[metric]) {
 997→						for i, val := range ser.Data {
 998→							if val.IsNaN() {
 999→								continue
1000→							} else {
1001→								collectorData[metric][i] += val
1002→							}
1003→						}
1004→					} else if okData {
1005→						cclog.Debugf("[SCHEMARESOLVER] clusterMetrics skip sum: data diff -> %s at %s; want size %d, have size %d", metric, ser.Hostname, len(collectorData[metric]), len(ser.Data))
1006→					}
1007→				}
1008→			}
1009→		}
1010→	}
1011→
1012→	for metricName, data := range collectorData {
1013→		// use ccUnits for backend normalization to "Tera"
1014→		p_old := ccunit.NewPrefix(collectorUnit[metricName].Prefix)
1015→		p_new := ccunit.NewPrefix("T")
1016→		convFunc := ccunit.GetPrefixPrefixFactor(p_old, p_new)
1017→		u_new := schema.Unit{Prefix: p_new.Prefix(), Base: collectorUnit[metricName].Base}
1018→
1019→		roundedData := make([]schema.Float, 0)
1020→		for _, v_old := range data {
1021→			v_new := math.Round(convFunc(float64(v_old)).(float64)*100.0) / 100.0
1022→			roundedData = append(roundedData, schema.Float(v_new))
1023→		}
1024→
1025→		cm := model.ClusterMetricWithName{
1026→			Name:     metricName,
1027→			Unit:     &u_new,
1028→			Timestep: collectorTimestep[metricName],
1029→			Data:     roundedData,
1030→		}
1031→
1032→		clusterMetrics.Metrics = append(clusterMetrics.Metrics, &cm)
1033→	}
1034→
1035→	return &clusterMetrics, nil
1036→}
