105→// Helper function for the jobsFootprints GraphQL query placed here so that schema.resolvers.go is not too full.
106→func (r *queryResolver) jobsFootprints(ctx context.Context, filter []*model.JobFilter, metrics []string) (*model.Footprints, error) {
107→	jobs, err := r.Repo.QueryJobs(ctx, filter, &model.PageRequest{Page: 1, ItemsPerPage: MAX_JOBS_FOR_ANALYSIS + 1}, nil)
108→	if err != nil {
109→		cclog.Error("Error while querying jobs for footprint")
110→		return nil, err
111→	}
112→	if len(jobs) > MAX_JOBS_FOR_ANALYSIS {
113→		return nil, fmt.Errorf("GRAPH/UTIL > too many jobs matched (max: %d)", MAX_JOBS_FOR_ANALYSIS)
114→	}
115→
116→	avgs := make([][]schema.Float, len(metrics))
117→	for i := range avgs {
118→		avgs[i] = make([]schema.Float, 0, len(jobs))
119→	}
120→
121→	timeweights := new(model.TimeWeights)
122→	timeweights.NodeHours = make([]schema.Float, 0, len(jobs))
123→	timeweights.AccHours = make([]schema.Float, 0, len(jobs))
124→	timeweights.CoreHours = make([]schema.Float, 0, len(jobs))
125→
126→	for _, job := range jobs {
127→		if job.MonitoringStatus == schema.MonitoringStatusDisabled || job.MonitoringStatus == schema.MonitoringStatusArchivingFailed {
128→			continue
129→		}
130→
131→		if err := metricdispatch.LoadAverages(job, metrics, avgs, ctx); err != nil {
132→			cclog.Error("Error while loading averages for footprint")
133→			return nil, err
134→		}
135→
136→		// #166 collect arrays: Null values or no null values?
137→		timeweights.NodeHours = append(timeweights.NodeHours, schema.Float(float64(job.Duration)/60.0*float64(job.NumNodes)))
138→		if job.NumAcc > 0 {
139→			timeweights.AccHours = append(timeweights.AccHours, schema.Float(float64(job.Duration)/60.0*float64(job.NumAcc)))
140→		} else {
141→			timeweights.AccHours = append(timeweights.AccHours, schema.Float(1.0))
142→		}
143→		if job.NumHWThreads > 0 {
144→			timeweights.CoreHours = append(timeweights.CoreHours, schema.Float(float64(job.Duration)/60.0*float64(job.NumHWThreads))) // SQLite HWThreads == Cores; numCoresForJob(job)
145→		} else {
146→			timeweights.CoreHours = append(timeweights.CoreHours, schema.Float(1.0))
147→		}
148→	}
149→
150→	res := make([]*model.MetricFootprints, len(avgs))
151→	for i, arr := range avgs {
152→		res[i] = &model.MetricFootprints{
153→			Metric: metrics[i],
154→			Data:   arr,
155→		}
156→	}
157→
158→	return &model.Footprints{
159→		TimeWeights: timeweights,
160→		Metrics:     res,
161→	}, nil
162→}
