260→  /* Functions */
261→  const updateConfigurationMutation = ({ name, value }) => {
262→    return mutationStore({
263→      client: client,
264→      query: gql`
265→        mutation ($name: String!, $value: String!) {
266→          updateConfiguration(name: $name, value: $value)
267→        }
268→      `,
269→      variables: { name, value },
270→    });
271→  };
272→
273→  function updateEntityConfiguration(select) {
274→    if (
275→      ccconfig[`analysisView_selectedTopEntity:${filterPresets.cluster}`] !=
276→      select
277→    ) {
278→      updateConfigurationMutation({
279→        name: `analysisView_selectedTopEntity:${filterPresets.cluster}`,
280→        value: JSON.stringify(select),
281→      }).subscribe((res) => {
282→        if (res.fetching === false && !res.error) {
283→          // console.log(`analysisView_selectedTopEntity:${filterPresets.cluster}` + ' -> Updated!')
284→        } else if (res.fetching === false && res.error) {
285→          throw res.error;
286→        }
287→      });
288→    } else {
289→      // console.log('No Mutation Required: Entity')
290→    }
291→  }
292→
293→  function updateCategoryConfiguration(select) {
294→    if (
295→      ccconfig[`analysisView_selectedTopCategory:${filterPresets.cluster}`] !=
296→      select
297→    ) {
298→      updateConfigurationMutation({
299→        name: `analysisView_selectedTopCategory:${filterPresets.cluster}`,
300→        value: JSON.stringify(select),
301→      }).subscribe((res) => {
302→        if (res.fetching === false && !res.error) {
303→          // console.log(`analysisView_selectedTopCategory:${filterPresets.cluster}` + ' -> Updated!')
304→        } else if (res.fetching === false && res.error) {
305→          throw res.error;
306→        }
307→      });
308→    } else {
309→      // console.log('No Mutation Required: Category')
310→    }
311→  }
312→
313→  function loadAvailable(globals, name) {
314→    const availableMetrics = new Set();
315→    if (globals && globals.length > 0) {
316→      for (let gm of globals) {
317→        if (gm.availability.find((av) => av.cluster == name)) {
318→          availableMetrics.add({name: gm.name, scope: gm.scope, unit: gm.unit});
319→        };
320→      }
321→    }
322→    return [...availableMetrics]
