  7→
  8→import (
  9→	"context"
 10→	"fmt"
 11→	"slices"
 12→	"sync"
 13→
 14→	"github.com/ClusterCockpit/cc-backend/internal/graph/model"
 15→)
 16→
 17→// statsGroupCache is a per-request cache for grouped JobsStatistics results.
 18→// It deduplicates identical (filter+groupBy) SQL queries that arise when the
 19→// frontend requests multiple sort/page slices of the same underlying data
 20→// (e.g. topUserJobs, topUserNodes, topUserAccs all group by USER).
 21→type statsGroupCache struct {
 22→	mu      sync.Mutex
 23→	entries map[string]*cacheEntry
 24→}
 25→
 26→type cacheEntry struct {
 27→	once   sync.Once
 28→	result []*model.JobsStatistics
 29→	err    error
 30→}
 31→
 32→type ctxKey int
 33→
 34→const statsGroupCacheKey ctxKey = iota
 35→
 36→// newStatsGroupCache creates a new empty cache.
 37→func newStatsGroupCache() *statsGroupCache {
 38→	return &statsGroupCache{
 39→		entries: make(map[string]*cacheEntry),
 40→	}
 41→}
 42→
 43→// WithStatsGroupCache injects a new cache into the context.
 44→func WithStatsGroupCache(ctx context.Context) context.Context {
 45→	return context.WithValue(ctx, statsGroupCacheKey, newStatsGroupCache())
 46→}
 47→
 48→// getStatsGroupCache retrieves the cache from context, or nil if absent.
 49→func getStatsGroupCache(ctx context.Context) *statsGroupCache {
 50→	if c, ok := ctx.Value(statsGroupCacheKey).(*statsGroupCache); ok {
 51→		return c
 52→	}
 53→	return nil
 54→}
 55→
 56→// cacheKey builds a deterministic string key from filter + groupBy + reqFields.
 57→func statsCacheKey(filter []*model.JobFilter, groupBy *model.Aggregate, reqFields map[string]bool) string {
 58→	return fmt.Sprintf("%v|%v|%v", filter, *groupBy, reqFields)
 59→}
 60→
 61→// getOrCompute returns cached results for the given key, computing them on
 62→// first access via the provided function.
 63→func (c *statsGroupCache) getOrCompute(
 64→	key string,
 65→	compute func() ([]*model.JobsStatistics, error),
 66→) ([]*model.JobsStatistics, error) {
 67→	c.mu.Lock()
 68→	entry, ok := c.entries[key]
 69→	if !ok {
 70→		entry = &cacheEntry{}
 71→		c.entries[key] = entry
 72→	}
 73→	c.mu.Unlock()
 74→
 75→	entry.once.Do(func() {
 76→		entry.result, entry.err = compute()
 77→	})
 78→	return entry.result, entry.err
 79→}
 80→
 81→// sortAndPageStats sorts a copy of allStats by the given sortBy field (descending)
 82→// and returns the requested page slice.
 83→func sortAndPageStats(allStats []*model.JobsStatistics, sortBy *model.SortByAggregate, page *model.PageRequest) []*model.JobsStatistics {
 84→	// Work on a shallow copy so the cached slice order is not mutated.
 85→	sorted := make([]*model.JobsStatistics, len(allStats))
 86→	copy(sorted, allStats)
 87→
 88→	if sortBy != nil {
 89→		getter := statsFieldGetter(*sortBy)
 90→		slices.SortFunc(sorted, func(a, b *model.JobsStatistics) int {
 91→			return getter(b) - getter(a) // descending
 92→		})
 93→	}
 94→
 95→	if page != nil && page.ItemsPerPage != -1 {
 96→		start := (page.Page - 1) * page.ItemsPerPage
 97→		if start >= len(sorted) {
 98→			return nil
 99→		}
100→		end := start + page.ItemsPerPage
101→		if end > len(sorted) {
102→			end = len(sorted)
103→		}
104→		sorted = sorted[start:end]
105→	}
106→
107→	return sorted
108→}
109→
110→// statsFieldGetter returns a function that extracts the sortable int field
111→// from a JobsStatistics struct for the given sort key.
112→func statsFieldGetter(sortBy model.SortByAggregate) func(*model.JobsStatistics) int {
113→	switch sortBy {
114→	case model.SortByAggregateTotaljobs:
115→		return func(s *model.JobsStatistics) int { return s.TotalJobs }
116→	case model.SortByAggregateTotalusers:
117→		return func(s *model.JobsStatistics) int { return s.TotalUsers }
118→	case model.SortByAggregateTotalwalltime:
119→		return func(s *model.JobsStatistics) int { return s.TotalWalltime }
120→	case model.SortByAggregateTotalnodes:
121→		return func(s *model.JobsStatistics) int { return s.TotalNodes }
122→	case model.SortByAggregateTotalnodehours:
123→		return func(s *model.JobsStatistics) int { return s.TotalNodeHours }
124→	case model.SortByAggregateTotalcores:
125→		return func(s *model.JobsStatistics) int { return s.TotalCores }
126→	case model.SortByAggregateTotalcorehours:
127→		return func(s *model.JobsStatistics) int { return s.TotalCoreHours }
128→	case model.SortByAggregateTotalaccs:
129→		return func(s *model.JobsStatistics) int { return s.TotalAccs }
130→	case model.SortByAggregateTotalacchours:
131→		return func(s *model.JobsStatistics) int { return s.TotalAccHours }
132→	default:
133→		return func(s *model.JobsStatistics) int { return s.TotalJobs }
134→	}
135→}
