 39→  /* Svelte 5 Props */
 40→  let {
 41→    type,
 42→    filterPresets
 43→  } = $props();
 44→
 45→  /* Const Init */
 46→  const {} = init();
 47→  const client = getContextClient();
 48→  const shortDuration = getContext("cc-config").jobList_hideShortRunningJobs; // Always configured
 49→
 50→  /* State Init*/
 51→  let filterComponent = $state(); // see why here: https://stackoverflow.com/questions/58287729/how-can-i-export-a-function-from-a-svelte-component-that-changes-a-value-in-the
 52→  let jobFilters = $state([]);
 53→  let nameFilter = $state("");
 54→  let sorting = $state({ field: "totalJobs", direction: "desc" });
 55→  let page = $state(1);
 56→  let itemsPerPage = $state(25);
 57→
 58→  /* Derived Vars */
 59→  const fetchRunning = $derived(jobFilters.some(jf => jf?.state?.length == 1 && jf?.state?.includes("running")));
 60→  const numCols = $derived.by(() => {
 61→    let colbase = 6
 62→    if (fetchRunning) {
 63→      colbase += 2
 64→    }
 65→    return colbase
 66→  })
 67→  const sortedRows = $derived(
 68→    $stats.data ? sort($stats.data.rows, sorting, nameFilter) : []
 69→  );
 70→  const paginatedRows = $derived(
 71→    sortedRows.slice((page - 1) * itemsPerPage, page * itemsPerPage)
 72→  );
 73→
 74→  /* Reset page when sorting or filter changes */
 75→  $effect(() => { sorting; nameFilter; page = 1; });
 76→
 77→  let stats = $derived(
 78→    queryStore({
 79→      client: client,
 80→      query: gql`
 81→        query($jobFilters: [JobFilter!]!, $fetchRunning: Boolean!) {
 82→          rows: jobsStatistics(filter: $jobFilters, groupBy: ${type}) {
 83→            id
 84→            name
 85→            totalJobs
 86→            shortJobs
 87→            totalCores @include(if: $fetchRunning)
 88→            totalAccs @include(if: $fetchRunning)
 89→            totalWalltime
 90→            totalCoreHours
 91→            totalAccHours
 92→          }
