110→      "Total Walltime",
111→      "Total Core Hours",
112→      "Total Accelerator Hours",
113→    ];
114→    const rows = sortedRows.map((row) => [
115→      row.id,
116→      ...(isUser ? [row?.name ?? ""] : []),
117→      row.totalJobs,
