123→    ]);
124→    const csv = [header, ...rows]
125→      .map((row) => row.map((v) => `"${String(v ?? "").replace(/"/g, '""')}"`).join(","))
126→      .join("\n");
127→    const blob = new Blob([csv], { type: "text/csv" });
