136→  function changeSorting(newField) {
137→    if (sorting.field == newField) {
138→      // Same Field, Change Direction
139→      sorting = { field: newField, direction: sorting.direction == "desc" ? "asc" : "desc" };
140→    } else {
141→      // Change Field, Apply Default Direction
142→      sorting = { field: newField, direction: "desc" };
143→    }
144→  }
145→
146→  function sort(stats, sorting, nameFilter) {
147→    const idCmp = sorting.direction == "asc"
148→      ? (a, b) => b.id.localeCompare(a.id)
149→      : (a, b) => a.id.localeCompare(b.id)
150→
151→    // Force empty or undefined strings to the end of the list
152→    const nameCmp = sorting.direction == "asc"
153→      ? (a, b) => !a?.name ? 1 : (!b?.name ? -1 : (b.name.localeCompare(a.name)))
154→      : (a, b) => !a?.name ? 1 : (!b?.name ? -1 : (a.name.localeCompare(b.name)))
155→
156→    const intCmp = sorting.direction == "asc"
157→      ? (a, b) => a[sorting.field] - b[sorting.field]
158→      : (a, b) => b[sorting.field] - a[sorting.field];
159→
160→    if (sorting.field == "id") {
161→      return stats.filter((u) => u.id.includes(nameFilter)).sort(idCmp)
162→    } else if (sorting.field == "name") {
163→      return stats.filter((u) => u.id.includes(nameFilter)).sort(nameCmp)
164→    } else {
165→      return stats.filter((u) => u.id.includes(nameFilter)).sort(intCmp)
166→    }
167→  }
168→
169→  /* On Mount */
170→  onMount(() => filterComponent.updateFilters());
171→</script>
